const PROCESSING_FEE = 5;
const FIRST_CONTRACT_INSURANCE_RATE = 0.1;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
};

const quotePremium = (items: Item[]): number => {
  const itemBaseSum = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const firstContractInsurance = itemBaseSum * FIRST_CONTRACT_INSURANCE_RATE;
  return Math.ceil(itemBaseSum + firstContractInsurance + PROCESSING_FEE);
};
